+
+    #[test]
+    fn grid_with_all_constraint_types() {
+        let grid = Grid::new()
+            .rows([
+                Constraint::Fixed(5),
+                Constraint::Percentage(20.0),
+                Constraint::Min(3),
+                Constraint::Max(10),
+                Constraint::Ratio(1, 4),
