+            assert!(
+                cell.right() <= area.right(),
+                "Cell ({},{}) right {} > area right {}",
+                row,
+                col,
+                cell.right(),
+                area.right()
+            );
+            assert!(
+                cell.bottom() <= area.bottom(),
+                "Cell ({},{}) bottom {} > area bottom {}",
+                row,
+                col,
+                cell.bottom(),
+                area.bottom()
+            );
+        }
+    }
+}

