+    impl Model for Counter {
+        type Message = CounterMsg;
+
+        fn update(&mut self, msg: Self::Message) -> Cmd<Self::Message> {
+            match msg {
+                CounterMsg::Increment => {
+                    self.value += 1;
+                    Cmd::none()
+                }
+                CounterMsg::Decrement => {
+                    self.value -= 1;
+                    Cmd::none()
+                }
+                CounterMsg::Quit => Cmd::quit(),
+            }
+        }
+
+        fn view(&self, _frame: &mut Frame) {}
+    }
